def process_and_get_max_datetime(table_name, filename_column="filename", default_datetime="2024-11-25T12:34:26.566833+0000"):
    df = spark.sql(f'select * from {table_name}')
    
    if filename_column in df.columns:
        processed_df = df.withColumn(
            "extracted_datetime",
            when(
                to_timestamp(
                    regexp_replace(
                        element_at(split(df[filename_column], "/"), -1),
                        r"appeal-has_|\.json",
                        ""
                    ),
                    "yyyy-MM-dd'T'HH:mm:ss.SSSSSSZ"
                ).isNotNull(),
                to_timestamp(
                    regexp_replace(
                        element_at(split(df[filename_column], "/"), -1),
                        r"appeal-has_|\.json",
                        ""
                    ),
                    "yyyy-MM-dd'T'HH:mm:ss.SSSSSSZ"
                )
            ).otherwise(lit(default_datetime).cast(TimestampType()))
        )
    else:
        processed_df = df.withColumn(
            "extracted_datetime",
            lit(default_datetime).cast(TimestampType())
        )
    
    max_datetime = processed_df.select(max("extracted_datetime")).collect()[0][0]
    if max_datetime is None:
        print("No valid datetime found. Using default datetime.")
        max_datetime = datetime.strptime(default_datetime, "%Y-%m-%dT%H:%M:%S.%f%z")
    
    return max_datetime.strftime("%Y-%m-%dT%H:%M:%S.%f%z")+'+0000'

# Usage
try:
    max_extracted_datetime = process_and_get_max_datetime(table_name)
    print(f"Max extracted datetime: {max_extracted_datetime}")
except Exception as e:
    print(f"An error occurred: {str(e)}")

def deep_ls(path: str, max_depth=1):
    """
    List all files and folders in specified path and
    subfolders within maximum recursion depth.
    """
    # List all files in path
    li = mssparkutils.fs.ls(path)

    # Return all files
    for x in li:
        if x.size != 0:
            yield x

    # If the max_depth has not been reached, start listing files and folders in subdirectories
    if max_depth > 1:
        for x in li:
            if x.size != 0:
                continue
            for y in deep_ls(x.path, max_depth - 1):
                yield y
